DROP TABLE IF EXISTS topic CASCADE;
DROP TABLE IF EXISTS region CASCADE;
DROP TABLE IF EXISTS jurisdiction CASCADE;
DROP TABLE IF EXISTS organization CASCADE;
DROP TABLE IF EXISTS document_type CASCADE;

ALTER TABLE document DROP CONSTRAINT IF EXISTS fk_document_organization;
ALTER TABLE document DROP CONSTRAINT IF EXISTS fk_document_document_type;
DROP INDEX IF EXISTS idx_document_organization_id;
ALTER TABLE document DROP COLUMN IF EXISTS organization_id;
ALTER TABLE document RENAME COLUMN document_type_id TO doc_type_id;
ALTER TABLE document ALTER COLUMN doc_type_id TYPE UUID USING doc_type_id::uuid;
ALTER TABLE document ADD CONSTRAINT document_doc_type_id_fkey FOREIGN KEY (doc_type_id) REFERENCES document_type(id);
ALTER TABLE document RENAME COLUMN valid_to TO signing_date;
ALTER TABLE document RENAME COLUMN publish_date TO publication_date;
ALTER TABLE document RENAME COLUMN valid_from TO effective_date;
ALTER TABLE document RENAME COLUMN summary TO abstract;
ALTER INDEX IF EXISTS idx_document_publish_date RENAME TO idx_document_publication_date;
ALTER INDEX IF EXISTS idx_document_valid_from RENAME TO idx_document_effective_date;

CREATE TABLE IF NOT EXISTS region_old (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    source_id UUID NOT NULL REFERENCES data_source(id) ON DELETE CASCADE,
    external_id VARCHAR(36) NOT NULL,
    name VARCHAR(255) NOT NULL,
    weight INTEGER NOT NULL DEFAULT 0,
    created_at TIMESTAMPTZ NOT NULL DEFAULT now(),
    UNIQUE (source_id, external_id)
);
INSERT INTO region_old (id, source_id, external_id, name, weight, created_at)
SELECT r.id, ds.id, r.external_id, r.name, r.weight, r.created_at
FROM region r CROSS JOIN data_source ds LIMIT 1;
DROP TABLE IF EXISTS region CASCADE;
ALTER TABLE region_old RENAME TO region;
